// src/pages/admin/AdminDashboard.js
import React, { useEffect, useState } from "react";
import { 
  getOverview, 
  getUsers, 
  getRiders, 
  getApprovedCaptains, 
  getPendingCaptains 
} from "../../services/adminApi";
import { useAuth } from "../../contexts/AuthContext"; // ensure this file is inside src/contexts

import { Button } from "@mui/material";

export default function AdminDashboard() {
  const { logout } = useAuth();
  const [overview, setOverview] = useState({});
  const [data, setData] = useState([]);
  const [activeTab, setActiveTab] = useState("overview");

  useEffect(() => {
    fetchOverview();
  }, []);

  const fetchOverview = async () => {
    try {
      const res = await getOverview();
      setOverview(res.data);
    } catch (err) {
      console.error("Overview fetch error:", err);
    }
  };

  const fetchData = async (type) => {
    setActiveTab(type);
    let res;
    try {
      if (type === "users") res = await getUsers();
      if (type === "riders") res = await getRiders();
      if (type === "captains") res = await getApprovedCaptains();
      if (type === "pending") res = await getPendingCaptains();
      setData(
        res?.data[
          type === "users"
            ? "users"
            : type === "riders"
            ? "riders"
            : type === "captains"
            ? "captains"
            : "pendingCaptains"
        ] || []
      );
    } catch (err) {
      console.error(`Error fetching ${type}:`, err);
      setData([]);
    }
  };

  return (
    <div style={{ padding: "20px" }}>
      <Button variant="contained" color="error" onClick={logout}>
        Logout
      </Button>

      <h1>Admin Dashboard</h1>

      <div style={{ margin: "20px 0" }}>
        <Button variant="outlined" onClick={() => fetchData("users")} style={{ marginRight: 10 }}>
          Users ({overview.users || 0})
        </Button>
        <Button variant="outlined" onClick={() => fetchData("riders")} style={{ marginRight: 10 }}>
          Riders ({overview.riders || 0})
        </Button>
        <Button variant="outlined" onClick={() => fetchData("captains")} style={{ marginRight: 10 }}>
          Approved Captains ({overview.captains || 0})
        </Button>
        <Button variant="outlined" onClick={() => fetchData("pending")} style={{ marginRight: 10 }}>
          Pending Captains ({overview.pendingCaptains || 0})
        </Button>
        <Button variant="outlined" onClick={() => fetchData("rides")}>
          Rides ({overview.rides || 0})
        </Button>
      </div>

      <table border="1" cellPadding="10" style={{ width: "100%", borderCollapse: "collapse" }}>
        <thead>
          <tr>
            <th>Name</th>
            <th>Email</th>
            <th>Mobile</th>
            <th>Role</th>
            <th>Approval Status</th>
          </tr>
        </thead>
        <tbody>
          {data.length === 0 && (
            <tr>
              <td colSpan="5" style={{ textAlign: "center" }}>
                No data found
              </td>
            </tr>
          )}
          {data.map((item) => (
            <tr key={item._id}>
              <td>{item.fullName}</td>
              <td>{item.email}</td>
              <td>{item.mobile}</td>
              <td>{item.role}</td>
              <td>{item.approvalStatus || "-"}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}
